async def run_import():
    full_content = "".join(content_parts).encode('utf-8')
    async with SessionLocal() as db:
        print("Importing property master data from embedded text...")
        result = await DataManagementService.import_property_master_csv(db, full_content)
        if result['status'] == 'success':
            print(f"Success! Imported {result.get('imported', 0)} new and updated {result.get('updated', 0)} properties.")
        else:
            print(f"Failed: {result['message']}")

if __name__ == "__main__":
    asyncio.run(run_import())
